## Mock EventSource Setup

```typescript
import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { SSEConnection, type SSEConnectionOptions } from '../sse-connection';

// Mock EventSource that exposes handlers for programmatic triggering
class MockEventSource {
  static instances: MockEventSource[] = [];
  url: string;
  readyState = EventSource.CONNECTING;
  onopen: ((event: Event) => void) | null = null;
  onerror: ((event: Event) => void) | null = null;
  private listeners = new Map<string, Array<(e: MessageEvent) => void>>();
  closed = false;

  constructor(url: string) {
    this.url = url;
    MockEventSource.instances.push(this);
  }

  addEventListener(type: string, handler: (e: MessageEvent) => void) {
    const list = this.listeners.get(type) ?? [];
    list.push(handler);
    this.listeners.set(type, list);
  }

  removeEventListener(type: string, handler: (e: MessageEvent) => void) {
    const list = this.listeners.get(type) ?? [];
    this.listeners.set(type, list.filter(h => h !== handler));
  }

  close() {
    this.closed = true;
    this.readyState = EventSource.CLOSED;
  }

  // Test helpers
  simulateOpen() {
    this.readyState = EventSource.OPEN;
    this.onopen?.(new Event('open'));
  }

  simulateError() {
    this.onerror?.(new Event('error'));
  }

  simulateEvent(type: string, data: unknown) {
    const handlers = this.listeners.get(type) ?? [];
    const event = new MessageEvent(type, { data: JSON.stringify(data) });
    for (const h of handlers) h(event);
  }
}

beforeEach(() => {
  MockEventSource.instances = [];
  vi.useFakeTimers();
  vi.stubGlobal('EventSource', MockEventSource);
  // Mock document.hidden and visibilitychange
  Object.defineProperty(document, 'hidden', { value: false, writable: true, configurable: true });
});

afterEach(() => {
  vi.useRealTimers();
  vi.unstubAllGlobals();
});
```

