Create a React hook that wraps the `SSEConnection` class, managing lifecycle, state exposure, and integration with `useTabVisibility`.

**File:** `apps/client/src/layers/shared/model/use-sse-connection.ts`

## Implementation

```typescript
import { useEffect, useRef, useState, useCallback } from 'react';
import type { ConnectionState } from '@dorkos/shared/types';
import { SSEConnection, type SSEConnectionOptions } from '../lib/transport/sse-connection';
import { SSE_RESILIENCE } from '../lib/constants';

export interface UseSSEConnectionOptions {
  /** Event handlers for SSE events. Should be a stable reference (useMemo). */
  eventHandlers: Record<string, (data: unknown) => void>;
  /** Enable page visibility optimization. Default: true. */
  visibilityOptimization?: boolean;
  /** Override heartbeat timeout (ms). Default: SSE_RESILIENCE.HEARTBEAT_TIMEOUT_MS. */
  heartbeatTimeoutMs?: number;
}

export interface UseSSEConnectionReturn {
  /** Current connection state. */
  connectionState: ConnectionState;
  /** Number of consecutive failed connection attempts. */
  failedAttempts: number;
  /** Timestamp (ms) of the last received event, or null if none received. */
  lastEventAt: number | null;
}

/**
 * Manage a resilient SSE connection with automatic reconnection, heartbeat watchdog, and visibility optimization.
 *
 * @param url - SSE endpoint URL. Pass `null` to disable (no connection created).
 * @param options - Configuration for event handling and behavior.
 * @returns Connection state and metadata for UI consumption.
 */
export function useSSEConnection(
  url: string | null,
  options: UseSSEConnectionOptions
): UseSSEConnectionReturn {
  const [connectionState, setConnectionState] = useState<ConnectionState>('connecting');
  const [failedAttempts, setFailedAttempts] = useState(0);
  const [lastEventAt, setLastEventAt] = useState<number | null>(null);

  // Capture handlers in refs to prevent reconnection on identity changes
  const eventHandlersRef = useRef(options.eventHandlers);
  eventHandlersRef.current = options.eventHandlers;

  const connectionRef = useRef<SSEConnection | null>(null);

  const visibilityOptimization = options.visibilityOptimization ?? true;
  const heartbeatTimeoutMs = options.heartbeatTimeoutMs ?? SSE_RESILIENCE.HEARTBEAT_TIMEOUT_MS;

  useEffect(() => {
    if (!url) {
      // No URL — reset state and don't connect
      setConnectionState('connecting');
      setFailedAttempts(0);
      setLastEventAt(null);
      return;
    }

    // Create a wrapper that delegates to the ref so handler identity changes
    // don't require recreating the SSEConnection
    const wrappedHandlers: Record<string, (data: unknown) => void> = {};
    for (const key of Object.keys(eventHandlersRef.current)) {
      wrappedHandlers[key] = (data: unknown) => {
        eventHandlersRef.current[key]?.(data);
      };
    }

    const connection = new SSEConnection(url, {
      eventHandlers: wrappedHandlers,
      onStateChange: (state, attempts) => {
        setConnectionState(state);
        setFailedAttempts(attempts);
      },
      heartbeatTimeoutMs,
    });

    if (visibilityOptimization) {
      connection.enableVisibilityOptimization();
    }

    connection.connect();
    connectionRef.current = connection;

    // Poll lastEventAt from the connection (cheap, driven by state changes)
    const updateLastEvent = setInterval(() => {
      const ts = connection.getLastEventAt();
      if (ts !== null) setLastEventAt(ts);
    }, 5000);

    return () => {
      clearInterval(updateLastEvent);
      connection.destroy();
      connectionRef.current = null;
    };
  }, [url, heartbeatTimeoutMs, visibilityOptimization]);

  return { connectionState, failedAttempts, lastEventAt };
}
```

## Barrel Export

Add to `apps/client/src/layers/shared/model/index.ts`:

```typescript
export {
  useSSEConnection,
  type UseSSEConnectionOptions,
  type UseSSEConnectionReturn,
} from './use-sse-connection';
```

## Key Design Decisions

1. **Ref-wrapped handlers**: The `eventHandlersRef` pattern ensures handler identity changes (common with inline callbacks) don't tear down and recreate the EventSource connection. The `useEffect` depends only on `url`, `heartbeatTimeoutMs`, and `visibilityOptimization`.

2. **null URL**: When `url` is `null`, no connection is created. This supports the session sync pattern where the URL is null during streaming or when no session is selected.

3. **Visibility integration**: The hook enables page visibility optimization by default. The `SSEConnection.enableVisibilityOptimization()` method handles the `visibilitychange` listener internally.

4. **lastEventAt polling**: Rather than adding a callback for every event just to update `lastEventAt`, we poll the SSEConnection's getter on a 5s interval. This is a minor optimization since `lastEventAt` is only used for tooltip display.

## Acceptance Criteria

- Hook creates SSEConnection on mount when url is non-null
- Hook calls destroy() on unmount
- Changing url creates a new connection (old one destroyed)
- Passing null url creates no connection
- connectionState and failedAttempts reflect SSEConnection state changes
- Handler identity changes do NOT cause reconnection
- visibilityOptimization defaults to true
- Hook is exported from `@/layers/shared/model`

