## Required Test Cases

```typescript
describe('useSSEConnection', () => {
  beforeEach(() => {
    vi.clearAllMocks();
  });

  it('creates SSEConnection and calls connect when url is provided', () => {
    renderHook(() => useSSEConnection('/api/stream', { eventHandlers: {} }));
    expect(SSEConnection).toHaveBeenCalledWith('/api/stream', expect.any(Object));
    expect(SSEConnection.prototype.connect).toHaveBeenCalled();
  });

  it('does not create connection when url is null', () => {
    renderHook(() => useSSEConnection(null, { eventHandlers: {} }));
    expect(SSEConnection).not.toHaveBeenCalled();
  });

  it('destroys connection on unmount', () => {
    const { unmount } = renderHook(() =>
      useSSEConnection('/api/stream', { eventHandlers: {} })
    );
    unmount();
    expect(SSEConnection.prototype.destroy).toHaveBeenCalled();
  });

  it('recreates connection when url changes', () => {
    const { rerender } = renderHook(
      ({ url }) => useSSEConnection(url, { eventHandlers: {} }),
      { initialProps: { url: '/api/stream/1' as string | null } }
    );
    expect(SSEConnection).toHaveBeenCalledTimes(1);

    rerender({ url: '/api/stream/2' });
    expect(SSEConnection.prototype.destroy).toHaveBeenCalled();
    expect(SSEConnection).toHaveBeenCalledTimes(2);
  });

  it('does not reconnect when handler identity changes', () => {
    const handler1 = { sync: vi.fn() };
    const handler2 = { sync: vi.fn() };
    const { rerender } = renderHook(
      ({ handlers }) => useSSEConnection('/api/stream', { eventHandlers: handlers }),
      { initialProps: { handlers: handler1 as Record<string, (data: unknown) => void> } }
    );
    rerender({ handlers: handler2 });
    // Only one SSEConnection instance should have been created
