      const payload = `id: ${eventId}\nevent: ${event.type}\ndata: ${JSON.stringify(event.data)}\n\n`;
      try {
        res.write(payload);
      } catch {
        // Connection may be closed
      }
    },
    clientId
  );

  res.on('close', () => {
    clearInterval(heartbeatInterval);
    unsubscribe();
  });
