  // Session lock — special handling (restore input, auto-clear)
  if ((err as { code?: string }).code === 'SESSION_LOCKED') {
    if (pendingUserIdRef.current) {
      const failedId = pendingUserIdRef.current;
      setMessages((prev) => prev.filter((m) => m.id !== failedId));
      pendingUserIdRef.current = null;
    }
    setSessionBusy(true);
    setError(errorInfo);
    if (clearInput) setInput(restoreContentOnLock);
    if (sessionBusyTimerRef.current) clearTimeout(sessionBusyTimerRef.current);
    sessionBusyTimerRef.current = setTimeout(() => {
      setSessionBusy(false);
      setError(null);
      sessionBusyTimerRef.current = null;
    }, TIMING.SESSION_BUSY_CLEAR_MS);
    setStatus('error');
    if (textStreamingTimerRef.current) clearTimeout(textStreamingTimerRef.current);
    isTextStreamingRef.current = false;
    setIsTextStreaming(false);
    setIsRateLimited(false);
    setRateLimitRetryAfter(null);
    retryCountRef.current = 0;
    return;
  }

  // Transient error — attempt auto-retry
  if (errorInfo.retryable && retryCountRef.current < SSE_RESILIENCE.POST_MAX_RETRIES) {
    retryCountRef.current++;
    setError({ ...errorInfo, heading: 'Retrying', message: 'Connection interrupted. Retrying...' });

    // Wait before retrying
    await new Promise((resolve) => setTimeout(resolve, SSE_RESILIENCE.POST_RETRY_DELAY_MS));

    // Retry the request — keep partial assistant response visible
    try {
      const finalContent = transformContentRef.current
        ? await transformContentRef.current(content)
        : content;

      await transport.sendMessage(
        targetSessionId,
        finalContent,
        (event) => streamEventHandler(event.type, event.data, assistantIdRef.current),
        new AbortController().signal,
        selectedCwdRef.current ?? undefined,
        { clientMessageId: pendingUserIdRef.current ?? undefined }
      );

      // Retry succeeded
      pendingUserIdRef.current = null;
      setStatus('idle');
      setError(null);
      retryCountRef.current = 0;
      return;
    } catch (retryErr) {
      if ((retryErr as Error).name === 'AbortError') {
        retryCountRef.current = 0;
        return;
      }
      // Retry failed — fall through to error display
      const retryErrorInfo = classifyTransportError(retryErr);
      setError({ ...retryErrorInfo, retryable: true });
    }
  } else {
    setError(errorInfo);
  }

  // Remove optimistic user message on final failure
  if (pendingUserIdRef.current) {
    const failedId = pendingUserIdRef.current;
    setMessages((prev) => prev.filter((m) => m.id !== failedId));
    pendingUserIdRef.current = null;
  }

  retryCountRef.current = 0;
  setStatus('error');
  if (textStreamingTimerRef.current) clearTimeout(textStreamingTimerRef.current);
  isTextStreamingRef.current = false;
  setIsTextStreaming(false);
  setIsRateLimited(false);
  setRateLimitRetryAfter(null);
}
