interface ConnectionStatusBannerProps {
  /** Current SSE connection state. */
  connectionState: ConnectionState;
  /** Number of consecutive failed attempts (shown during reconnection). */
  failedAttempts?: number;
  /** Maximum attempts before disconnected (shown as denominator). */
  maxAttempts?: number;
  /** Additional CSS classes. */
  className?: string;
}

/**
 * Inline status banner for degraded or lost SSE connections.
 *
 * Shows nothing when connected or initially connecting. Shows an amber
 * reconnection indicator or a red disconnection warning.
 */
export function ConnectionStatusBanner({
  connectionState,
  failedAttempts,
  maxAttempts,
  className,
}: ConnectionStatusBannerProps) {
  if (connectionState === 'connected' || connectionState === 'connecting') return null;

  const isDisconnected = connectionState === 'disconnected';
  const attemptText =
    failedAttempts && maxAttempts
      ? ` (attempt ${failedAttempts}/${maxAttempts})`
      : '';

  return (
    <div
      className={cn(
        'flex items-center gap-2 rounded-md px-3 py-1.5 text-xs font-medium',
        isDisconnected
          ? 'bg-red-500/10 text-red-600 dark:text-red-400'
          : 'bg-amber-500/10 text-amber-600 dark:text-amber-400',
        className
      )}
    >
      {isDisconnected ? (
        <WifiOff className="size-3.5" />
      ) : (
        <Wifi className="size-3.5 animate-pulse" />
      )}
      <span>
        {isDisconnected
          ? 'Connection lost. Check your network.'
          : `Reconnecting...${attemptText}`}
      </span>
    </div>
  );
}
